"); } else { fwrite($fp,"\${$row['varname']} = '".str_replace("'",'',$row['value'])."';
"); } } fwrite($fp,"?".">"); fclose($fp); } //保存配置的改动 if($dopost=="save") { if(!isset($token)){ echo 'No token found!'; exit; } if(strcasecmp($token, $_SESSION['token']) !== 0){ echo 'Token mismatch!'; exit; } foreach($_POST as $k=>$v) { if(preg_match("#^edit___#", $k)) { $v = cn_substrR(${$k}, 1024); } else { continue; } $k = preg_replace("#^edit___#", "", $k); $dsql->ExecuteNoneQuery("UPDATE `#@__sysconfig` SET `value`='$v' WHERE varname='$k' "); } ReWriteConfig(); ShowMsg("成功更改站点配置！", "sys_info.php"); exit(); } //增加新变量 else if($dopost=='add') { if(!isset($token)){ echo 'No token found!'; exit; } if(strcasecmp($token, $_SESSION['token']) !== 0){ echo 'Token mismatch!'; exit; } if($vartype=='bool' && ($nvarvalue!='Y' && $nvarvalue!='N')) { ShowMsg("布尔变量值必须为'Y'或'N'!","-1"); exit(); } if(trim($nvarname)=='' || preg_match("#[^a-z_]#i", $nvarname) ) { ShowMsg("变量名不能为空并且必须为[a-z_]组成!","-1"); exit(); } $row = $dsql->GetOne("SELECT varname FROM `#@__sysconfig` WHERE varname LIKE '$nvarname' "); if(is_array($row)) { ShowMsg("该变量名称已经存在!","-1"); exit(); } $row = $dsql->GetOne("SELECT aid FROM `#@__sysconfig` ORDER BY aid DESC "); $aid = $row['aid'] + 1; $inquery = "INSERT INTO `#@__sysconfig`(`aid`,`varname`,`info`,`value`,`type`,`groupid`) VALUES ('$aid','$nvarname','$varmsg','$nvarvalue','$vartype','$vargroup')"; $rs = $dsql->ExecuteNoneQuery($inquery); if(!$rs) { ShowMsg("新增变量失败，可能有非法字符！", "sys_info.php?gp=$vargroup"); exit(); } if(!is_writeable($configfile)) { ShowMsg("成功保存变量，但由于 $configfile 无法写入，因此不能更新配置文件！","sys_info.php?gp=$vargroup"); exit(); }else { ReWriteConfig(); ShowMsg("成功保存变量并更新配置文件！","sys_info.php?gp=$vargroup"); exit(); } } make_hash(); include DedeInclude('templets/sys_info.htm'); 简单浏览一遍，除了在更新配置的地方使用str_replace("'",'',$row['value'])进行对'的替换过滤，新增变量有着对非法字符的检查外，其实并没有特别的检查。 并且看到了明显的 fwrite($fp,"<"."?php
